INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('sk4oaylixybj', NULL, 'six-months-at-the-dream-job-then-a-layoff-email', 'career', 'Six months at the dream job, then a layoff email', 'I left a stable role for the company I had been chasing for two years. I gave it everything: late nights, weekends, side projects nobody asked for. Six months in, my manager forwarded a calendar invite from HR. I spent three weeks pretending it had not happened. I still do not know what I did wrong, or if I did anything at all.', 'en', 1, 'published', 0, '{"metoo":2,"hug":2,"strength":1,"respect":1,"solidarity":0}', 0, 1, 1772680109);
