INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('so0qxyctrl22', NULL, 'burned-out-at-a-big-tech-job-and-did-not-notice-for-a-year', 'career', 'Burned out at a big tech job and did not notice for a year', 'I was hitting every metric. Promotions, comp bumps, public praise. By month nine I was sleeping four hours and snapping at my partner. My therapist asked when I had last taken a weekend off. I genuinely could not remember. I took medical leave, came back, quit eight weeks later. The job had not changed. I had.', 'en', 1, 'published', 0, '{"metoo":0,"hug":1,"strength":1,"respect":2,"solidarity":0}', 0, 1, 1770792520);
