INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('soaohwfebu8y', NULL, 'i-quit-my-stable-job-for-nothing-concrete', 'career', 'I quit my stable job for nothing concrete', 'I left a well-paid role to figure things out. I had savings, a vague plan, and a lot of confidence. Eighteen months later I am interviewing for the same kind of job I left, two levels lower, explaining a gap I cannot make sound interesting. The freedom was real. So is the regret.', 'en', 1, 'published', 0, '{"metoo":1,"hug":4,"strength":3,"respect":2,"solidarity":0}', 0, 1, 1776772442);
