INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('srxx7v6brcmu', NULL, 'one-bad-keynote-ended-my-career-trajectory', 'career', 'One bad keynote ended my career trajectory', 'All-hands, fifteen minutes, my biggest project. I froze on the second slide. Stumbled the rest. Nobody said anything directly. But the next quarter my scope shrank. The quarter after that, my manager started copying my skip-level on emails. By year-end I was not staffed on anything that mattered. I left a year later.', 'en', 1, 'published', 0, '{"metoo":22,"hug":19,"strength":9,"respect":9,"solidarity":4}', 0, 1, 1774809311);
