INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('s8ecqrhbnb8o', NULL, 'passed-over-for-promotion-three-years-in-a-row', 'career', 'Passed over for promotion three years in a row', 'First time, I told myself the timing was off. Second time, the role was not quite right. Third time, my new manager pulled me aside and asked if this was the right ladder for me. I am still here. I do not know if I am staying because I want to, or because leaving feels like proof he was right.', 'en', 1, 'published', 0, '{"metoo":0,"hug":0,"strength":1,"respect":0,"solidarity":0}', 0, 1, 1777173955);
INSERT INTO reactions (id, post_id, user_id, session_hash, type, created_at) VALUES ('rxrqychm9yja', 's8ecqrhbnb8o', NULL, 'seed:8m0brgsn6a', 'strength', 1777177844);
INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('sr69egk4aomm', NULL, 'career-pivot-at-35-did-not-work-out', 'career', 'Career pivot at 35 did not work out', 'Engineering for fifteen years, then I burned out and pivoted into UX. Took loans for a bootcamp, did the portfolio, made the case in interviews. Two years and four jobs later, I am back in engineering. The pivot was not wrong. I was. I wanted to want it. Turns out that is not enough.', 'en', 1, 'published', 0, '{"metoo":1,"hug":4,"strength":3,"respect":0,"solidarity":2}', 0, 1, 1776690282);
