INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('s8keukr0mokk', NULL, 'my-boss-hated-me-and-i-never-figured-out-why', 'career', 'My boss hated me and I never figured out why', 'From day one she found something to fix in everything I did. I tried adapting, then documenting, then keeping my head down. None of it worked. I left a year later thinking I had dodged something. The new place is fine. But I still wake up sometimes wondering what she actually saw.', 'en', 1, 'published', 0, '{"metoo":0,"hug":2,"strength":0,"respect":0,"solidarity":0}', 0, 1, 1767645657);
