INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('sh217avf6hvg', NULL, 'i-chose-money-over-the-work-i-loved', 'career', 'I chose money over the work I loved', 'I left a research lab where I was happy for a corporate role that paid eighty percent more. The work is fine. The people are fine. The money is, as promised, very nice. I have not read a paper for fun in two years. I do not recognize what I do anymore. Money fixed exactly the problems I named, and none of the ones I did not.', 'en', 1, 'published', 0, '{"metoo":2,"hug":0,"strength":0,"respect":0,"solidarity":0}', 0, 1, 1775138108);
