INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('s0qycut4b765', NULL, 'we-ran-out-of-runway-with-no-warning-signs', 'business', 'We ran out of runway with no warning signs', 'We had what we thought was twelve months of runway. The CFO had been hiding a payroll miscalculation for two quarters. Real number was three months. We told the team on a Thursday. By Monday, half had already lined up interviews. I learned more about cash flow in those eight weeks than in the four years before.', 'en', 1, 'published', 0, '{"metoo":0,"hug":0,"strength":2,"respect":1,"solidarity":0}', 0, 1, 1776997028);
INSERT INTO reactions (id, post_id, user_id, session_hash, type, created_at) VALUES ('r75g6gz7g41a', 's0qycut4b765', NULL, 'seed:lb7s52f26t', 'strength', 1777029212);
