INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('swuzjerkwuu5', NULL, 'my-co-founder-breakup-killed-the-company', 'business', 'My co-founder breakup killed the company', 'We met in grad school and built the thing over five years. Then we disagreed about a fundraise. Then a hire. Then everything. Lawyers got involved. The company kept running for six months, but it was already dead. I lost a co-founder, a company, and the closest friend I had, in that order.', 'en', 1, 'published', 0, '{"metoo":3,"hug":1,"strength":0,"respect":0,"solidarity":2}', 0, 1, 1767692329);
