INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('svz8yr5xukon', NULL, 'launch-day-was-completely-silent', 'business', 'Launch day was completely silent', 'Two years of building. Press kit, launch video, beta list of four thousand people. Tuesday morning the post went up. By Friday we had done three hundred dollars in revenue and eleven signups. I refreshed analytics for a month before admitting nobody was coming. The product was not bad. Nobody just wanted it.', 'en', 1, 'published', 0, '{"metoo":2,"hug":1,"strength":1,"respect":0,"solidarity":1}', 0, 1, 1775375168);
