INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('stpqcggcjpwe', NULL, 'sued-by-the-competitor-we-were-trying-to-beat', 'business', 'Sued by the competitor we were trying to beat', 'We were small. They were huge. We launched a feature that competed with one of theirs. Their lawyers sent forty pages. Our lawyers said we would probably win, but it would cost more than we had. We took the feature down, lost the customers it had brought in, and shipped nothing for three months. We never recovered the momentum.', 'en', 1, 'published', 0, '{"metoo":0,"hug":1,"strength":3,"respect":1,"solidarity":0}', 0, 1, 1772052581);
