INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('s8rf8i82ad38', NULL, 'we-pivoted-six-months-too-late', 'business', 'We pivoted six months too late', 'We had data showing the original product was not working in month four. We pivoted in month fourteen. By then half the team had quit, the board had stopped returning emails, and the new direction needed money we no longer had a way to raise. The pivot would have worked at month five. By the time we tried, the runway was gone.', 'en', 1, 'published', 0, '{"metoo":9,"hug":5,"strength":5,"respect":4,"solidarity":5}', 0, 1, 1777084583);
