INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('sjcy2o6mytsg', NULL, 'three-years-of-long-distance-ended-in-one-phone-call', 'relationships', 'Three years of long-distance ended in one phone call', 'Three years across two oceans. We had the spreadsheet of visits, the shared playlists, the saved screenshots. I was on a layover when I read her message. I did not even land before it was over. Six months later we both moved to the same city, separately, for unrelated reasons. We have never met up.', 'en', 1, 'published', 0, '{"metoo":2,"hug":1,"strength":1,"respect":3,"solidarity":1}', 0, 1, 1777189901);
