INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('sokovssk2rg5', NULL, 'i-lost-my-best-friend-over-two-thousand-dollars', 'relationships', 'I lost my best friend over two thousand dollars', 'He needed it for rent. I had it. I did not make a contract because we were friends and that is what the loan was supposed to mean. Eighteen months later I am still asking, getting promises, getting nothing. I would give back the money to have the friendship. He would give back the friendship to keep the money. We both already lost both.', 'en', 1, 'published', 0, '{"metoo":4,"hug":1,"strength":2,"respect":1,"solidarity":1}', 0, 1, 1774437894);
