INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('snh2b5bftddr', NULL, 'i-knew-on-my-wedding-day', 'relationships', 'I knew on my wedding day', 'I knew during the rehearsal dinner. I knew during the ceremony. I told myself it was nerves. We made it three years before the divorce papers. The hardest thing is not the wasted time. It is that I knew, and I went through with it anyway. I still cannot explain to anyone, including myself, why.', 'en', 1, 'published', 0, '{"metoo":7,"hug":5,"strength":4,"respect":2,"solidarity":8}', 0, 1, 1773991209);
