INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('ssu7mlzfqjld', NULL, 'my-family-cut-me-off-when-i-needed-them-most', 'relationships', 'My family cut me off when I needed them most', 'I came out at twenty-three. My parents said they needed time. Three years of time later, my mother sent a card on my birthday with no note. That was last year. I have a chosen family now and they are wonderful. But the original wound does not close just because you build something good around it.', 'en', 1, 'published', 0, '{"metoo":0,"hug":1,"strength":0,"respect":0,"solidarity":0}', 0, 1, 1771945837);
INSERT INTO reactions (id, post_id, user_id, session_hash, type, created_at) VALUES ('rz54dvb28o7x', 'ssu7mlzfqjld', NULL, 'seed:lodhelcyl7', 'hug', 1774980883);
INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('stihupeweds4', NULL, 'moved-cities-and-never-made-a-single-friend', 'relationships', 'Moved cities and never made a single friend', 'Took the relocation, took the bigger paycheck, told myself the social part would sort itself out. Two years in, I had colleagues, no friends, and a calendar with nothing on weekends. I had forgotten how to make friends as an adult. Or maybe I had never known, and the old ones had just always been there.', 'en', 1, 'published', 0, '{"metoo":3,"hug":2,"strength":2,"respect":1,"solidarity":1}', 0, 1, 1771685033);
