INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('s8ozlp4wfjm6', NULL, 'walked-away-from-my-phd-after-four-years', 'education', 'Walked away from my PhD after four years', 'Year one, the topic excited me. Year three, I was avoiding my advisor''s emails. Year four, I sat in the library and realized I had not opened my notes in two months. I emailed the registrar, said I was withdrawing, walked out before I could change my mind. I tell people I have a master''s now. I am still embarrassed.', 'en', 1, 'published', 0, '{"metoo":7,"hug":11,"strength":2,"respect":1,"solidarity":2}', 0, 1, 1777128633);
