INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('s811q8tihh5m', NULL, 'failed-the-bar-exam-twice', 'education', 'Failed the bar exam twice', 'First time, I had been studying for six months and missed by twelve points. Second time, I had quit my job to study full-time and missed by four. The pass list came out and I scrolled until I was sure. My parents had told everyone. Nobody knew what to say to me at dinner that night. I did not know what to say either.', 'en', 1, 'published', 0, '{"metoo":20,"hug":10,"strength":10,"respect":7,"solidarity":4}', 0, 1, 1767951288);
