INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('s24y9cgsssth', NULL, 'picked-the-wrong-major-and-did-not-realize-until-year-four', 'education', 'Picked the wrong major and did not realize until year four', 'Picked it because my dad picked it. Hated it from semester one. Stayed because switching meant two more years and admitting I was wrong. Graduated with a degree I have never used. Eight years on, I work in something completely different. Those four years are not ruined. They are just not why I am where I am.', 'en', 1, 'published', 0, '{"metoo":0,"hug":1,"strength":0,"respect":0,"solidarity":0}', 0, 1, 1771331976);
INSERT INTO reactions (id, post_id, user_id, session_hash, type, created_at) VALUES ('rboh6wji66yu', 's24y9cgsssth', NULL, 'seed:op0h16li91', 'hug', 1773147146);
INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('s9fvoovfds46', NULL, 'i-never-finished-my-thesis', 'education', 'I never finished my thesis', 'I had two chapters left. My data was solid. My advisor said one more push. I pushed for eight months and produced nothing usable. Asked for an extension. Then another. The day I missed my third deadline, I realized I was not going to finish, ever. I emailed my advisor. He said he was not surprised. Neither was I.', 'en', 1, 'published', 0, '{"metoo":1,"hug":1,"strength":4,"respect":0,"solidarity":0}', 0, 1, 1773464451);
