INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('swdegtp068ee', NULL, 'crypto-wiped-out-my-entire-savings', 'financial', 'Crypto wiped out my entire savings', 'I bought in 2021 because everyone I trusted was buying in 2021. I held when it dipped because that is what you do. Then it dipped more. Then more. I am down to about eight percent of what I put in. The dollar amount is not life-ruining. The emotional cost of looking at the chart for two years is something I cannot price.', 'en', 1, 'published', 0, '{"metoo":0,"hug":0,"strength":0,"respect":0,"solidarity":0}', 0, 1, 1767074503);
INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('scsrxz1em5cu', NULL, 'i-bought-a-house-at-the-absolute-peak', 'financial', 'I bought a house at the absolute peak', 'Closed in March, peak rate, peak price. The mortgage is twice what rent would have been. I am not underwater on paper, but I would lose money if I sold. I tell myself it is a long game. The math says I might be right in fifteen years. The math does not say anything about the next fifteen years of payments.', 'en', 1, 'published', 0, '{"metoo":14,"hug":13,"strength":3,"respect":5,"solidarity":4}', 0, 1, 1777020394);
