INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('sx2a8q5cl9w3', NULL, 'took-a-loan-for-a-course-that-taught-me-nothing', 'financial', 'Took a loan for a course that taught me nothing', 'Eight thousand dollars, twelve weeks, no-code SaaS in ninety days. The instructor was good at marketing. The curriculum was a YouTube playlist with a Notion doc. I built nothing, learned nothing useful, and still owe most of the loan. The lesson cost more than the course did.', 'en', 1, 'published', 0, '{"metoo":0,"hug":0,"strength":1,"respect":0,"solidarity":0}', 0, 1, 1776726557);
INSERT INTO reactions (id, post_id, user_id, session_hash, type, created_at) VALUES ('rvgx65blrm37', 'sx2a8q5cl9w3', NULL, 'seed:pku83i7tgu', 'strength', 1776731244);
INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('sz79xhliiirf', NULL, 'a-scammer-took-my-emergency-fund', 'financial', 'A scammer took my emergency fund', 'I got an email that looked like it came from my bank. I had just moved, my account info was in flux, the timing made sense. I clicked. I entered. By the time I called the real bank, the money was gone. Insurance covered some. Most of it did not come back. I rebuilt the fund over two years and I still flinch at every email I get.', 'en', 1, 'published', 0, '{"metoo":1,"hug":0,"strength":0,"respect":0,"solidarity":1}', 0, 1, 1776732318);
INSERT INTO reactions (id, post_id, user_id, session_hash, type, created_at) VALUES ('ry1rd5extq9z', 'sz79xhliiirf', NULL, 'seed:8cb71dvox8', 'metoo', 1776823299);
