INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('s7acm8nvckm2', NULL, 'i-ignored-burnout-until-i-could-not-get-out-of-bed', 'health', 'I ignored burnout until I could not get out of bed', 'I told myself I was just tired. For about eighteen months. Then I could not get out of bed for a week. Took unpaid leave. Could not tell anyone the real reason. The doctor said burnout is a process, not an event. The event was just where I noticed it. The process had been running the whole time.', 'en', 1, 'published', 0, '{"metoo":2,"hug":1,"strength":0,"respect":0,"solidarity":0}', 0, 1, 1776787398);
