INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('sl4wtl6opvcx', NULL, 'ten-years-of-diet-and-gym-yo-yo', 'health', 'Ten years of diet and gym yo-yo', 'I have lost the same fifteen pounds maybe seven times. New plan, six weeks of discipline, a slip, a slide, a year of nothing, repeat. I can recite macros from memory. I have three gym memberships across two cities. The mechanical part is not the problem. I just do not know how to want this consistently for more than a season.', 'en', 1, 'published', 0, '{"metoo":0,"hug":2,"strength":2,"respect":0,"solidarity":0}', 0, 1, 1775461196);
