INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('s7dlisfnmpog', NULL, 'a-mental-health-spiral-i-could-not-pull-out-of', 'health', 'A mental health spiral I could not pull out of', 'I had been okay for years. Then a hard month became a hard quarter became a year I mostly do not remember. I stopped answering messages. I stopped showering some days. The thing that scared me most was how reasonable it all felt while it was happening. I am out now. The line between fine and not fine is thinner than I used to think.', 'en', 1, 'published', 0, '{"metoo":4,"hug":3,"strength":1,"respect":2,"solidarity":0}', 0, 1, 1771405119);
