INSERT INTO posts (id, user_id, slug, category, title, body, locale, is_anonymous, status, flag_count, reaction_counts, pinned, is_seed, created_at) VALUES ('ssypxr98jgca', NULL, 'moved-to-my-dream-city-and-hated-everything-about-it', 'other', 'Moved to my dream city and hated everything about it', 'I had dreamed about this city for a decade. Took the job, sold the car, bought a one-way ticket. Three months in, I realized the version of the city I loved was the one in my head, not the one I was in. The weather, the rents, the loneliness — none of it was a surprise on paper. All of it was a surprise in person.', 'en', 1, 'published', 0, '{"metoo":0,"hug":1,"strength":3,"respect":1,"solidarity":0}', 0, 1, 1775501709);
